impl PromptInitCommand {
    pub fn run(&self) -> Result<()> {
        let snippet = match self.shell {
            Shell::Bash => self.bash_snippet(),
            Shell::Zsh => self.zsh_snippet(),
            Shell::Fish => self.fish_snippet(),
            Shell::PowerShell => self.powershell_snippet(),
        };

        println!("{}", snippet);
        println!("\n# Add the above to your shell configuration file");
        Ok(())
    }
}
