 {"id":"coding_agent_usage_tracker-m5r","title":"Status: Add contextual error messages with status correlation","description":"## Summary
Enhance error messages with context from provider status to help users understand failures.

## Background
When fetches fail, users want to know:
1. Is this a provider-side issue or local?
2. Is the provider having an outage?
3. What should I do?

By correlating errors with status data, we provide actionable information.

## Technical Design

### Error Contextualization
```rust
pub struct ContextualError {
    pub original: FetchError,
    pub status: Option<StatusPayload>,
    pub context: ErrorContext,
    pub suggestion: String,
}

pub enum ErrorContext {
    ProviderOutage,       // Status page confirms issue
    PossibleOutage,       // Error suggests provider issue
    AuthenticationError,  // Credentials issue
    NetworkError,         // Local network problem
    RateLimited,          // Rate limit hit
    Unknown,              // Cannot determine
}

impl ContextualError {
    pub fn from_fetch_error(
        error: FetchError,
        status: Option<&StatusPayload>,
    ) -> Self {
        let (context, suggestion) = Self::analyze(&error, status);

        Self {
            original: error,
            status: status.cloned(),
            context,
            suggestion,
        }
    }

    fn analyze(
        error: &FetchError,
        status: Option<&StatusPayload>,
    ) -> (ErrorContext, String) {
        // Check if provider has active incident
        if let Some(s) = status {
            if matches!(s.indicator, StatusIndicator::Major | StatusIndicator::Critical) {
                return (
                    ErrorContext::ProviderOutage,
                    format!(
                        "Provider is experiencing issues: {}. Check {} for updates.",
                        s.description.as_deref().unwrap_or("service disruption"),
                        s.url
                    ),
                );
            }
        }

        // Analyze error type
        match error {
            FetchError::AuthFailed(_) => (
                ErrorContext::AuthenticationError,
                "Authentication failed. Try re-authenticating with your provider.".to_string(),
            ),
            FetchError::RateLimited(_) => (
                ErrorContext::RateLimited,
                "Rate limit exceeded. Wait before retrying.".to_string(),
            ),
            FetchError::NetworkError(e) => {
                if e.is_timeout() {
                    (
                        ErrorContext::PossibleOutage,
                        "Request timed out. Provider may be experiencing issues.".to_string(),
                    )
                } else if e.is_connect() {
                    (
                        ErrorContext::NetworkError,
                        "Connection failed. Check your network.".to_string(),
                    )
                } else {
                    (ErrorContext::Unknown, "Network error occurred.".to_string())
                }
            }
            FetchError::ServerError(code) if *code >= 500 => (
                ErrorContext::PossibleOutage,
                format!("Server returned {}. Provider may be having issues.", code),
            ),
            _ => (
                ErrorContext::Unknown,
                "An error occurred. Try again later.".to_string(),
            ),
        }
    }
}
```

### Display Integration
```rust
impl fmt::Display for ContextualError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        // Show original error
        writeln!(f, "Error: {}", self.original)?;

        // Show context
        match self.context {
            ErrorContext::ProviderOutage => {
                writeln!(f, "⚠️  Provider is experiencing an outage")?;
            }
            ErrorContext::PossibleOutage => {
                writeln!(f, "⚠️  Provider may be experiencing issues")?;
            }
            ErrorContext::AuthenticationError => {
                writeln!(f, "🔑 Authentication problem detected")?;
            }
            ErrorContext::RateLimited => {
                writeln!(f, "⏳ Rate limit exceeded")?;
            }
            _ => {}
        }

        // Show suggestion
        writeln!(f, "💡 {}", self.suggestion)?;

        // Show status if relevant
        if let Some(status) = &self.status {
            if !matches!(status.indicator, StatusIndicator::None | StatusIndicator::Unknown) {
                writeln!(f, "📊 Current status: {} - {}",
                    status.indicator,
                    status.description.as_deref().unwrap_or("unknown")
                )?;
            }
        }

        Ok(())
    }
}
```

